def search_products(keyword: str, db: Session):
    return db.query(Product).filter(
        Product.name.like(f"%{keyword}%")
    ).all()

def delete_record(model, id: int, db: Session):
    record = db.query(model).filter(
        model.id == id
    ).first()
    if record:
        db.delete(record)
        db.commit()

